var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하아……! 하아……! 하아……!","JPN":"はあ……はあ……はあ……！","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"呼呼……呼呼……呼……！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"실장님! 괜찮아요?!","JPN":"室長！　大丈夫ですか？","ENG":"Chief! Are you okay?!","TWN":"室長！你沒事吧？！"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"죽을 것 같지만……. 당장은 괜찮다고 해 둘게요.","JPN":"かなりまずい状態ではありますが……今のところは大丈夫だと言っておきます。","ENG":"Not really... But I’ll say that I am for now.","TWN":"雖然快死掉了……現在就先當我沒事吧！"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"부축해 드리겠습니다. 일어나세요, 실장님.","JPN":"さあ、手を。私が支えます、室長。","ENG":"Here, take my hand, Chief.","TWN":"室長，我來扶你起來。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"고맙네요……. 배신자 딱지는 이제 떼도 될까요?","JPN":"ありがとうございます。裏切り者のレッテルはもう剥がしてもいいでしょうか？","ENG":"Thanks... Now, may I stop being called a traitor?","TWN":"謝謝……我現在可以撕掉叛徒的標籤了嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더가 판단할 문제이지만 정신을 잃은 상태라서요. 무사히 돌아가면 그 때 얘기하죠.","JPN":"リーダーが判断すべき問題ですが、気を失った状態ですので。\\n無事に帰ったらその時話しましょう。","ENG":"That’s for Leader to decide, but she’s kind of unconscious right now. We’ll talk about it once we’re out of here.","TWN":"這必須由老大來判斷，但她現在尚未清醒。等安全回到公司後再說吧。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"지금은 한가하게 수다 떨 때가 아니니까요.","JPN":"今はのんびりおしゃべりをしている場合ではありませんので。","ENG":"Right now, there are other matters to attend to.","TWN":"現在還不是悠哉聊天的時候。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭…… 불여시 같은 것……!","JPN":"くぅ……ずる賢いやつめ……！","ENG":"Krr... You vixen...!","TWN":"哼……臭丫頭……！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내가 카운터란 게 처음으로 고마운 순간이었어. 일반인이면 뼛가루도 안 남았을 테니까.","JPN":"私がカウンターであることに初めて感謝した瞬間だったわ。\\n一般人なら骨すら残っていなかった。","ENG":"This is the first time I’m glad that I’m a Counter. A normal person would’ve died from that attack.","TWN":"我還是第一次覺得還好她是制裁者，否則要是普通人的話，應該早就屍骨無存吧？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"체크메이트까지는…… 한 수 모자랐지만 말이지.","JPN":"チェックメイトまでは……一手及ばなかったけどね。","ENG":"Guess you were one move off from a checkmate.","TWN":"雖然離將軍……還差一步。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"쿨럭……!","JPN":"コホッ……！","ENG":"*Cough*","TWN":"咳咳……！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이제 포기하세요, 바이오닉스 대표.","JPN":"もう観念してください、バイオニクス代表。","ENG":"Surrender yourself, CEO of Bionics.","TWN":"仿生代表，收手吧！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 장치 없이는…… 아가씨에게 더 이상 암시를 걸 수 없는 것 아닌가요?","JPN":"その装置が無ければ……お嬢様にこれ以上暗示をかけられないのでは？","ENG":"Without that... You can no longer control Miss Jia.","TWN":"沒有那個裝置……你就無法再對小姐下令吧？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래. 하지만 너희들이 가진 패도 전부 바닥난 것 같은데.","JPN":"そうね。でも、あんたたちが持っている手札も底をついたようだけど。","ENG":"True, but I believe you’ve also showed me your hand too, no?","TWN":"話是沒錯，不過你們牌都已經出了吧？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"원래 계획은 지아가 직접 너희를 전부 죽이게 만드는 거였지만……","JPN":"元の計画だと、ユイちゃんの手であんたたちを皆殺しにする予定だったけど……","ENG":"I was originally going to make Jia kill all of you...","TWN":"雖然照原本的計畫，是要讓小佳親手殺光你們……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}}]`);export{e as default};